starterCode.css:
// Starter CSS for Accessible Breadcrumb Component
/* Tailwind CSS classes are used for styling */

<nav aria-label="Breadcrumb">
  ol {
    list-style: none;
    padding: 0;
    margin: 0;
  }

  li {
    display: inline-block;
    padding: 0.5rem;
    border-radius: 0.25rem;
    background-color: #f0f0f0;
  }

  li::before {
    content: "\203a \00a0";
    margin-right: 0.25rem;
  }

  li:first-child {
    padding-left: 0;
  }

  li:last-child {
    padding-right: 0;
  }

  li a {
    color: #333;
    text-decoration: none;
  }

  li a:hover {
    color: #666;
  }

  li[aria-current="location"] {
    padding: 0.5rem;
    border-radius: 1rem;
    background-color: #ddd;
  }

  li[aria-current="location"]::before {
    content: none;
  }

  button {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 0.25rem;
    background-color: #4CAF50;
    color: #fff;
    cursor: pointer;
  }

  button:hover {
    background-color: #3e8e41;
  }
</nav>

starterCode.javascript:
// Starter JavaScript for Accessible Breadcrumb Component
const breadcrumbContainer = document.querySelector('.border-2.p-4.mt-10.rounded');

// Add breadcrumb item
function addBreadcrumbItem(text) {
  const breadcrumbItem = document.createElement('li');
  breadcrumbItem.innerHTML = text;
  breadcrumbContainer.appendChild(breadcrumbItem);
}

// Add breadcrumb item with visually hidden label and link
function addBreadcrumbItemWithLabel(text) {
  const breadcrumbItem = document.createElement('li')
  breadcrumbItem.innerHTML = `<span class="sr-only">${text}</span><a href="#" role="menuitem" aria-label="${text}">${text}</a>`;
  breadcrumbContainer.appendChild(breadcrumbItem);
}

// Add current page indicator
function addCurrentPageIndicator() {
  const currentPageIndicator = document.createElement('li')
  currentPageIndicator.setAttribute('aria-current', 'location');
  currentPageIndicator.innerHTML = `<span class="sr-only">Current page</span>`;
  breadcrumbContainer.appendChild(currentPageIndicator);
}

// Add focusable element for navigation
function addFocusableElement() {
  const focusableElement = document.createElement('button')
  focusableElement.innerHTML = 'Back';
  focusableElement.classList.add('ml-auto', 'p-2', 'bg-blue-500', 'hover:bg-blue-700', 'text-white', 'rounded')
  breadcrumbContainer.appendChild(focusableElement);
}

