jsAccessibility: // JavaScript for Accessibility
function checkAccessibility() {
  // Check for visually hidden labels
  const breadcrumbItems = document.querySelectorAll('li a');
  breadcrumbItems.forEach(breadcrumbItem => {
    if (breadcrumbItem.textContent === breadcrumbItem.getAttribute('aria-label')) {
      console.error('Visually hidden label for breadcrumb item is missing.');
    }
  });

  // Check for aria labels
  const ariaLabels = document.querySelectorAll('[aria-label]');
  ariaLabels.forEach(ariaLabel => {
    if (ariaLabel.textContent !== ariaLabel.getAttribute('aria-label')) {
      console.error('Aria label is not accessible.');
    }
  });

  // Check for current page indicator
  const currentPageIndicator = document.querySelector('li[aria-current="location"]');
  if (!currentPageIndicator) {
    console.error('Current page indicator is missing.');
  }
}

// Run accessibility checks
document.addEventListener('DOMContentLoaded', checkAccessibility);
